def solve(input_str):
    max_len = 0
    path_lens = {0: 0}
    for line in input_str.split('\n'):
        depth = line.count('\t')
        name = line.replace('\t', '')
        if '.' in name:
            max_len = max(max_len, path_lens[depth] + len(name))
        else:
            path_lens[depth + 1] = path_lens[depth] + len(name) + 1
    return max_len

